```javascript
const { Client, Intents } = require('discord.js');

const client = new Client({ intents: [Intents.FLAGS.GUILDS] });

client.once('ready', () => {
  console.log('Bot is ready!');
});

client.on('interactionCreate', async (interaction) => {
  if (!interaction.isCommand()) return;

  if (interaction.commandName === 'ban') {
    const user = interaction.options.getUser('user');

    if (user) {
      await interaction.guild.members.ban(user.id);
      interaction.reply(`Banned ${user.tag}`);
    } else {
      interaction.reply('Invalid user specified');
    }
  }
});

client.login('YOUR_BOT_TOKEN');
```

Replace 'YOUR_BOT_TOKEN' with your actual bot token. Don't forget to invite the bot to your server and give it the necessary permissions. Happy coding!

